import path from 'path';
import fs from 'fs';
import { fileURLToPath } from 'url';
import Database from 'bun:sqlite';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const port = process.env.DASHBOARD_PORT || 3000;
const distDir = path.join(__dirname, 'dist');
const dbPath = '/workspace/data/twitter_agent.db';

const mimeTypes = {
  '.html': 'text/html',
  '.js': 'application/javascript',
  '.css': 'text/css',
  '.json': 'application/json',
  '.png': 'image/png',
  '.jpg': 'image/jpeg',
  '.svg': 'image/svg+xml',
  '.ico': 'image/x-icon',
  '.woff': 'font/woff',
  '.woff2': 'font/woff2',
};

function getDb() {
  return new Database(dbPath);
}

function serveStatic(pathname) {
  let filePath = path.join(distDir, pathname === '/' ? 'index.html' : pathname);

  try {
    const stat = fs.statSync(filePath);
    if (stat.isDirectory()) {
      filePath = path.join(filePath, 'index.html');
    }
  } catch {
    if (pathname.startsWith('/api/') || pathname.startsWith('/api')) {
      return new Response('Not Found', { status: 404 });
    }
    filePath = path.join(distDir, 'index.html');
  }

  try {
    const content = fs.readFileSync(filePath);
    const ext = path.extname(filePath);
    return new Response(content, {
      headers: { 'Content-Type': mimeTypes[ext] || 'application/octet-stream' },
    });
  } catch {
    return new Response('Not Found', { status: 404 });
  }
}

// API handlers
function getFocusAccounts() {
  const db = getDb();
  const accounts = db.query(`
    SELECT id, username, display_name, notes, active, created_at
    FROM focus_accounts
    ORDER BY created_at DESC
  `).all();
  db.close();
  return Response.json(accounts);
}

function addFocusAccount(username, notes = null) {
  const db = getDb();
  try {
    db.query(`
      INSERT INTO focus_accounts (username, notes)
      VALUES (?, ?)
    `).run(username.replace('@', ''), notes);
    db.close();
    return Response.json({ success: true });
  } catch (e) {
    db.close();
    return Response.json({ success: false, error: e.message }, { status: 400 });
  }
}

function updateFocusAccount(id, data) {
  const db = getDb();
  try {
    if (data.active !== undefined) {
      db.query('UPDATE focus_accounts SET active = ? WHERE id = ?').run(data.active ? 1 : 0, id);
    }
    if (data.notes !== undefined) {
      db.query('UPDATE focus_accounts SET notes = ? WHERE id = ?').run(data.notes, id);
    }
    db.close();
    return Response.json({ success: true });
  } catch (e) {
    db.close();
    return Response.json({ success: false, error: e.message }, { status: 400 });
  }
}

function deleteFocusAccount(id) {
  const db = getDb();
  try {
    db.query('DELETE FROM focus_accounts WHERE id = ?').run(id);
    db.close();
    return Response.json({ success: true });
  } catch (e) {
    db.close();
    return Response.json({ success: false, error: e.message }, { status: 400 });
  }
}

function getPendingComments() {
  const db = getDb();
  const comments = db.query(`
    SELECT
      sc.id,
      sc.suggested_text,
      sc.status,
      sc.created_at as comment_created_at,
      p.id as post_db_id,
      p.post_id,
      p.account_username,
      p.post_text,
      p.post_url,
      p.posted_at
    FROM suggested_comments sc
    JOIN posts p ON sc.post_id = p.id
    WHERE sc.status = 'pending'
    ORDER BY p.posted_at DESC
  `).all();
  db.close();
  return Response.json(comments);
}

function getAllComments() {
  const db = getDb();
  const comments = db.query(`
    SELECT
      sc.id,
      sc.suggested_text,
      sc.status,
      sc.created_at as comment_created_at,
      sc.updated_at,
      p.id as post_db_id,
      p.post_id,
      p.account_username,
      p.post_text,
      p.post_url,
      p.posted_at
    FROM suggested_comments sc
    JOIN posts p ON sc.post_id = p.id
    ORDER BY sc.created_at DESC
  `).all();
  db.close();
  return Response.json(comments);
}

function updateComment(id, data) {
  const db = getDb();
  try {
    if (data.status) {
      db.query('UPDATE suggested_comments SET status = ?, updated_at = CURRENT_TIMESTAMP WHERE id = ?').run(data.status, id);
    }
    if (data.suggested_text !== undefined) {
      db.query('UPDATE suggested_comments SET suggested_text = ?, updated_at = CURRENT_TIMESTAMP WHERE id = ?').run(data.suggested_text, id);
    }
    db.close();
    return Response.json({ success: true });
  } catch (e) {
    db.close();
    return Response.json({ success: false, error: e.message }, { status: 400 });
  }
}

function getStats() {
  const db = getDb();
  const stats = {
    totalAccounts: db.query('SELECT COUNT(*) as count FROM focus_accounts WHERE active = 1').get().count,
    totalPosts: db.query('SELECT COUNT(*) as count FROM posts').get().count,
    pendingComments: db.query('SELECT COUNT(*) as count FROM suggested_comments WHERE status = "pending"').get().count,
    doneComments: db.query('SELECT COUNT(*) as count FROM suggested_comments WHERE status = "done"').get().count,
    dismissedComments: db.query('SELECT COUNT(*) as count FROM suggested_comments WHERE status = "dismissed"').get().count,
  };
  db.close();
  return Response.json(stats);
}

const server = Bun.serve({
  port,
  async fetch(req) {
    const url = new URL(req.url);
    const method = req.method;

    // API Routes
    if (url.pathname === '/api/accounts' && method === 'GET') {
      return getFocusAccounts();
    }

    if (url.pathname === '/api/accounts' && method === 'POST') {
      const body = await req.json();
      return addFocusAccount(body.username, body.notes);
    }

    if (url.pathname.startsWith('/api/accounts/') && method === 'PUT') {
      const id = parseInt(url.pathname.split('/')[3]);
      const body = await req.json();
      return updateFocusAccount(id, body);
    }

    if (url.pathname.startsWith('/api/accounts/') && method === 'DELETE') {
      const id = parseInt(url.pathname.split('/')[3]);
      return deleteFocusAccount(id);
    }

    if (url.pathname === '/api/comments' && method === 'GET') {
      return getAllComments();
    }

    if (url.pathname === '/api/comments/pending' && method === 'GET') {
      return getPendingComments();
    }

    if (url.pathname.startsWith('/api/comments/') && method === 'PUT') {
      const id = parseInt(url.pathname.split('/')[3]);
      const body = await req.json();
      return updateComment(id, body);
    }

    if (url.pathname === '/api/stats' && method === 'GET') {
      return getStats();
    }

    return serveStatic(url.pathname);
  },
});

console.log(`Dashboard server running on http://localhost:${port}`);

