import React, { useState, useEffect } from 'react';

// Helper to format relative time
function timeAgo(dateString) {
  if (!dateString) return 'Unknown';
  const date = new Date(dateString);
  const now = new Date();
  const seconds = Math.floor((now - date) / 1000);

  if (seconds < 60) return 'just now';
  const minutes = Math.floor(seconds / 60);
  if (minutes < 60) return `${minutes}m ago`;
  const hours = Math.floor(minutes / 60);
  if (hours < 24) return `${hours}h ago`;
  const days = Math.floor(hours / 24);
  if (days < 7) return `${days}d ago`;
  return date.toLocaleDateString();
}

// Stats component
function Stats({ stats }) {
  return (
    <div style={styles.statsContainer}>
      <div style={styles.statCard}>
        <div style={styles.statNumber}>{stats.totalAccounts}</div>
        <div style={styles.statLabel}>Focus Accounts</div>
      </div>
      <div style={styles.statCard}>
        <div style={styles.statNumber}>{stats.totalPosts}</div>
        <div style={styles.statLabel}>Posts Tracked</div>
      </div>
      <div style={{ ...styles.statCard, backgroundColor: '#fef3c7' }}>
        <div style={{ ...styles.statNumber, color: '#d97706' }}>{stats.pendingComments}</div>
        <div style={styles.statLabel}>Pending</div>
      </div>
      <div style={{ ...styles.statCard, backgroundColor: '#d1fae5' }}>
        <div style={{ ...styles.statNumber, color: '#059669' }}>{stats.doneComments}</div>
        <div style={styles.statLabel}>Commented</div>
      </div>
    </div>
  );
}

// Focus Accounts section
function FocusAccounts({ accounts, onRefresh }) {
  const [newUsername, setNewUsername] = useState('');
  const [newNotes, setNewNotes] = useState('');
  const [isAdding, setIsAdding] = useState(false);

  const handleAdd = async (e) => {
    e.preventDefault();
    if (!newUsername.trim()) return;

    await fetch('api/accounts', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ username: newUsername, notes: newNotes || null }),
    });

    setNewUsername('');
    setNewNotes('');
    setIsAdding(false);
    onRefresh();
  };

  const toggleActive = async (id, currentActive) => {
    await fetch(`api/accounts/${id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ active: !currentActive }),
    });
    onRefresh();
  };

  const deleteAccount = async (id) => {
    if (!confirm('Delete this focus account?')) return;
    await fetch(`api/accounts/${id}`, { method: 'DELETE' });
    onRefresh();
  };

  return (
    <div style={styles.section}>
      <div style={styles.sectionHeader}>
        <h2 style={styles.sectionTitle}>Focus Accounts</h2>
        <button style={styles.addButton} onClick={() => setIsAdding(!isAdding)}>
          {isAdding ? 'Cancel' : '+ Add Account'}
        </button>
      </div>

      {isAdding && (
        <form onSubmit={handleAdd} style={styles.addForm}>
          <input
            type="text"
            placeholder="@username"
            value={newUsername}
            onChange={(e) => setNewUsername(e.target.value)}
            style={styles.input}
          />
          <input
            type="text"
            placeholder="Notes (optional)"
            value={newNotes}
            onChange={(e) => setNewNotes(e.target.value)}
            style={{ ...styles.input, flex: 2 }}
          />
          <button type="submit" style={styles.submitButton}>Add</button>
        </form>
      )}

      <div style={styles.accountsList}>
        {accounts.length === 0 ? (
          <p style={styles.emptyState}>No focus accounts yet. Add some to get started!</p>
        ) : (
          accounts.map((account) => (
            <div key={account.id} style={{
              ...styles.accountCard,
              opacity: account.active ? 1 : 0.5,
            }}>
              <div style={styles.accountInfo}>
                <a
                  href={`https://x.com/${account.username}`}
                  target="_blank"
                  rel="noopener noreferrer"
                  style={styles.username}
                >
                  @{account.username}
                </a>
                {account.notes && <span style={styles.notes}>{account.notes}</span>}
              </div>
              <div style={styles.accountActions}>
                <button
                  onClick={() => toggleActive(account.id, account.active)}
                  style={account.active ? styles.activeButton : styles.inactiveButton}
                >
                  {account.active ? 'Active' : 'Paused'}
                </button>
                <button
                  onClick={() => deleteAccount(account.id)}
                  style={styles.deleteButton}
                >
                  Delete
                </button>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

// Pending Comments section
function PendingComments({ comments, onRefresh }) {
  const [editingId, setEditingId] = useState(null);
  const [editText, setEditText] = useState('');

  const startEditing = (comment) => {
    setEditingId(comment.id);
    setEditText(comment.suggested_text);
  };

  const saveEdit = async (id) => {
    await fetch(`api/comments/${id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ suggested_text: editText }),
    });
    setEditingId(null);
    onRefresh();
  };

  const updateStatus = async (id, status) => {
    await fetch(`api/comments/${id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status }),
    });
    onRefresh();
  };

  const copyToClipboard = (text) => {
    navigator.clipboard.writeText(text);
  };

  return (
    <div style={styles.section}>
      <div style={styles.sectionHeader}>
        <h2 style={styles.sectionTitle}>Pending Comments</h2>
        <span style={styles.badge}>{comments.length} pending</span>
      </div>

      {comments.length === 0 ? (
        <p style={styles.emptyState}>
          No pending comments. Use the <code>/twitter-comments fetch</code> skill to generate new comment suggestions.
        </p>
      ) : (
        <div style={styles.commentsTable}>
          {comments.map((comment) => (
            <div key={comment.id} style={styles.commentRow}>
              <div style={styles.postSection}>
                <div style={styles.postHeader}>
                  <a
                    href={`https://x.com/${comment.account_username}`}
                    target="_blank"
                    rel="noopener noreferrer"
                    style={styles.postAuthor}
                  >
                    @{comment.account_username}
                  </a>
                  <span style={styles.postAge}>{timeAgo(comment.posted_at)}</span>
                </div>
                <p style={styles.postText}>{comment.post_text}</p>
                <a
                  href={comment.post_url}
                  target="_blank"
                  rel="noopener noreferrer"
                  style={styles.postLink}
                >
                  View on X
                </a>
              </div>

              <div style={styles.commentSection}>
                <div style={styles.commentLabel}>Suggested Comment:</div>
                {editingId === comment.id ? (
                  <div style={styles.editContainer}>
                    <textarea
                      value={editText}
                      onChange={(e) => setEditText(e.target.value)}
                      style={styles.editTextarea}
                      rows={3}
                    />
                    <div style={styles.editActions}>
                      <button onClick={() => saveEdit(comment.id)} style={styles.saveButton}>Save</button>
                      <button onClick={() => setEditingId(null)} style={styles.cancelButton}>Cancel</button>
                    </div>
                  </div>
                ) : (
                  <div style={styles.commentText}>
                    {comment.suggested_text}
                    <button
                      onClick={() => startEditing(comment)}
                      style={styles.editButton}
                      title="Edit"
                    >
                      Edit
                    </button>
                  </div>
                )}

                <div style={styles.actionButtons}>
                  <button
                    onClick={() => copyToClipboard(comment.suggested_text)}
                    style={styles.copyButton}
                  >
                    Copy
                  </button>
                  <button
                    onClick={() => updateStatus(comment.id, 'done')}
                    style={styles.doneButton}
                  >
                    Done (Commented)
                  </button>
                  <button
                    onClick={() => updateStatus(comment.id, 'dismissed')}
                    style={styles.dismissButton}
                  >
                    Dismiss
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

// Main App
export default function App() {
  const [stats, setStats] = useState({
    totalAccounts: 0,
    totalPosts: 0,
    pendingComments: 0,
    doneComments: 0,
    dismissedComments: 0,
  });
  const [accounts, setAccounts] = useState([]);
  const [comments, setComments] = useState([]);
  const [activeTab, setActiveTab] = useState('pending');

  const fetchData = async () => {
    const [statsRes, accountsRes, commentsRes] = await Promise.all([
      fetch('api/stats'),
      fetch('api/accounts'),
      fetch('api/comments/pending'),
    ]);

    setStats(await statsRes.json());
    setAccounts(await accountsRes.json());
    setComments(await commentsRes.json());
  };

  useEffect(() => {
    fetchData();
    // Refresh every 30 seconds
    const interval = setInterval(fetchData, 30000);
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={styles.container}>
      <header style={styles.header}>
        <h1 style={styles.title}>X/Twitter Growth Agent</h1>
        <p style={styles.subtitle}>Monitor focus accounts and manage comment suggestions</p>
      </header>

      <Stats stats={stats} />

      <div style={styles.tabs}>
        <button
          style={activeTab === 'pending' ? styles.tabActive : styles.tab}
          onClick={() => setActiveTab('pending')}
        >
          Pending Comments
        </button>
        <button
          style={activeTab === 'accounts' ? styles.tabActive : styles.tab}
          onClick={() => setActiveTab('accounts')}
        >
          Focus Accounts
        </button>
      </div>

      {activeTab === 'pending' && (
        <PendingComments comments={comments} onRefresh={fetchData} />
      )}

      {activeTab === 'accounts' && (
        <FocusAccounts accounts={accounts} onRefresh={fetchData} />
      )}

      <footer style={styles.footer}>
        <p>Use <code>/twitter-comments fetch</code> to fetch new posts and generate comments</p>
      </footer>
    </div>
  );
}

